    case 4:
      DoCheckFakeData<int32>(audio_data, length);
      break;
    case 2:
      DoCheckFakeData<int16>(audio_data, length);
      break;
    case 1:
      DoCheckFakeData<uint8>(audio_data, length);
      break;
    default:
      NOTREACHED() << "Unsupported audio bit depth in crossfade.";
  }
}

